3.2 SkuInfo.java文件 com.swj.search.model;import org.springframework.data.elasticsearch.annotations.Document;import org.springframework.data.elasticsearch.annotations.Field;import org.springframework.data.elasticsearch.annotations.FieldType;import javax.persistence.Id;import java.io.Serializable;import java.util.Date;import java.util.Map;@Document(indexName = "skuinfo", type = "docs")public class SkuInfo implements Serializable &#123;    //商品id，同时也是商品编号    @Id    @Field(index = true, store = true, type = FieldType.Keyword)    private Long id;    //SKU名称    @Field(index = true, store = true, type = FieldType.Text, analyzer = "ik_smart")    private String name;    //商品价格，单位为：元    @Field(index = true, store = true, type = FieldType.Double)    private Long price;    //库存数量    @Field(index = true, store = true, type = FieldType.Integer)    private Integer num;    //商品图片    @Field(index = false, store = true, type = FieldType.Text)    private String image;    //商品状态，1-正常，2-下架，3-删除    @Field(index = true, store = true, type = FieldType.Keyword)    private String status;    //创建时间    private Date createTime;    //更新时间    private Date updateTime;    //是否默认    @Field(index = true, store = true, type = FieldType.Keyword)    private String isDefault;    //SPUID    @Field(index = true, store = true, type = FieldType.Long)    private Long spuId;    //类目ID    @Field(index = true, store = true, type = FieldType.Long)    private Long categoryId;    //类目名称    @Field(index = true, store = true, type = FieldType.Keyword)    private String categoryName;    //品牌名称    @Field(index = true, store = true, type = FieldType.Keyword)    private String brandName;    //规格    private String spec;    //规格参数    private Map&lt;String, Object&gt; specMap;    public Long getId() &#123;        return id;    &#125;    public void setId(Long id) &#123;        this.id = id;    &#125;    public String getName() &#123;        return name;    &#125;    public void setName(String name) &#123;        this.name = name;    &#125;    public Long getPrice() &#123;        return price;    &#125;    public void setPrice(Long price) &#123;        this.price = price;    &#125;    public Integer getNum() &#123;        return num;    &#125;    public void setNum(Integer num) &#123;        this.num = num;    &#125;    public String getImage() &#123;        return image;    &#125;    public void setImage(String image) &#123;        this.image = image;    &#125;    public String getStatus() &#123;        return status;    &#125;    public void setStatus(String status) &#123;        this.status = status;    &#125;    public Date getCreateTime() &#123;        return createTime;    &#125;    public void setCreateTime(Date createTime) &#123;        this.createTime = createTime;    &#125;    public Date getUpdateTime() &#123;        return updateTime;    &#125;    public void setUpdateTime(Date updateTime) &#123;        this.updateTime = updateTime;    &#125;    public String getIsDefault() &#123;        return isDefault;    &#125;    public void setIsDefault(String isDefault) &#123;        this.isDefault = isDefault;    &#125;    public Long getSpuId() &#123;        return spuId;    &#125;    public void setSpuId(Long spuId) &#123;        this.spuId = spuId;    &#125;    public Long getCategoryId() &#123;        return categoryId;    &#125;    public void setCategoryId(Long categoryId) &#123;        this.categoryId = categoryId;    &#125;    public String getCategoryName() &#123;        return categoryName;    &#125;    public void setCategoryName(String categoryName) &#123;        this.categoryName = categoryName;    &#125;    public String getBrandName() &#123;        return brandName;    &#125;    public void setBrandName(String brandName) &#123;        this.brandName = brandName;    &#125;    public String getSpec() &#123;        return spec;    &#125;    public void setSpec(String spec) &#123;        this.spec = spec;    &#125;    public Map&lt;String, Object&gt; getSpecMap() &#123;        return specMap;    &#125;    public void setSpecMap(Map&lt;String, Object&gt; specMap) &#123;        this.specMap = specMap;    &#125;&#125;
