3.4 ESManagerServiceImpl.java文件1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253package com.swj.search.service.impl;import com.alibaba.fastjson.JSON;import com.swj.crawler.fegin.SKUFegin;import com.swj.crawler.model.TbSku;import com.swj.search.mapper.ESManagerMapper;import com.swj.search.model.SkuInfo;import com.swj.search.service.ESManagerService;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.data.elasticsearch.core.ElasticsearchTemplate;import org.springframework.stereotype.Service;import java.util.List;import java.util.Map;@Servicepublic class ESManagerServiceImpl implements ESManagerService &#123;  @Autowired private ElasticsearchTemplate elasticsearchTemplate;  @Autowired private SKUFegin skuFegin;  @Autowired private ESManagerMapper esManagerMapper;  // 创建索引库结构  @Override  public void createMappingAndIndex() &#123;    // 创建索引    elasticsearchTemplate.createIndex(SkuInfo.class);    // 创建映射    elasticsearchTemplate.putMapping(SkuInfo.class);  &#125;  @Override  public void importAll() &#123;    // 查询sku集合    List&lt;TbSku&gt; tbSkus = skuFegin.selectAll();    String jsonTbSkus = JSON.toJSONString(tbSkus);    List&lt;SkuInfo&gt; skuInfos = JSON.parseArray(jsonTbSkus, SkuInfo.class);    for (SkuInfo skuInfo : skuInfos) &#123;      Map spaceMap = JSON.parseObject(skuInfo.getSpec(), Map.class);      skuInfo.setSpecMap(spaceMap);    &#125;    // 导入索引库    esManagerMapper.saveAll(skuInfos);  &#125;  @Override  public void importDataBySpuId(String spuId) &#123;&#125;  @Override  public void delDataBySpuId(String spuId) &#123;&#125;&#125;
3.4 SearchServiceImpl.java文件123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107package com.swj.search.service.impl;import com.alibaba.fastjson.JSON;import com.swj.search.model.SkuInfo;import com.swj.search.service.SearchService;import org.apache.commons.lang.StringUtils;import org.elasticsearch.action.search.SearchResponse;import org.elasticsearch.index.query.BoolQueryBuilder;import org.elasticsearch.index.query.Operator;import org.elasticsearch.index.query.QueryBuilders;import org.elasticsearch.search.SearchHit;import org.elasticsearch.search.SearchHits;import org.elasticsearch.search.fetch.subphase.highlight.HighlightField;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.data.domain.Pageable;import org.springframework.data.elasticsearch.core.ElasticsearchTemplate;import org.springframework.data.elasticsearch.core.SearchResultMapper;import org.springframework.data.elasticsearch.core.aggregation.AggregatedPage;import org.springframework.data.elasticsearch.core.aggregation.impl.AggregatedPageImpl;import org.springframework.data.elasticsearch.core.query.NativeSearchQueryBuilder;import org.springframework.lang.Nullable;import org.springframework.stereotype.Service;import java.util.ArrayList;import java.util.HashMap;import java.util.List;import java.util.Map;@Servicepublic class SearchServiceImpl implements SearchService &#123;  @Autowired private ElasticsearchTemplate elasticsearchTemplate;  @Override  public Map search(Map&lt;String, String&gt; searchMap) &#123;    Map&lt;String, Object&gt; resultMap = new HashMap&lt;&gt;();    if (searchMap != null) &#123;      // 构建查询条件      NativeSearchQueryBuilder nativeSearchQueryBuilder = new NativeSearchQueryBuilder();      BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();      // 按照关键字查询      if (StringUtils.isNotEmpty(searchMap.get("keywords"))) &#123;        boolQuery.must(            QueryBuilders.matchQuery("name", searchMap.get("keywords")).operator(Operator.AND));      &#125;      // 按照品牌进行过滤查询      if (StringUtils.isNotEmpty(searchMap.get("brand"))) &#123;        boolQuery.filter(QueryBuilders.termQuery("brandName", searchMap.get("brand")));      &#125;      // 范围查询      if (StringUtils.isNotEmpty(searchMap.get("price"))) &#123;        String[] prices = searchMap.get("price").split("-");        if (prices.length == 2) &#123;          boolQuery.filter(QueryBuilders.rangeQuery("price").lte(prices[0]));        &#125;        boolQuery.filter(QueryBuilders.rangeQuery("price").gte(prices[1]));      &#125;      nativeSearchQueryBuilder.withQuery(boolQuery);      // 开启查询      /** 第一个参数: 条件构建对象 第二个参数: 查询操作实体类 第三个参数: 查询结果操作对象 */      // 封装查询结果      AggregatedPage&lt;SkuInfo&gt; aggregatedPage =          elasticsearchTemplate.queryForPage(              nativeSearchQueryBuilder.build(),              SkuInfo.class,              new SearchResultMapper() &#123;                @Override                public &lt;T&gt; AggregatedPage&lt;T&gt; mapResults(                    SearchResponse searchResponse, Class&lt;T&gt; aClass, Pageable pageable) &#123;                  List list = new ArrayList();                  // 获取查询结果集                  SearchHits searchHits = searchResponse.getHits();                  for (SearchHit searchHit : searchHits) &#123;                    if (searchHit != null) &#123;                      SkuInfo skuInfo = JSON.parseObject(searchHit.toString(), SkuInfo.class);                      Map&lt;String, HighlightField&gt; highlightFields = searchHit.getHighlightFields();                      if (highlightFields != null &amp;&amp; highlightFields.size() &gt; 0) &#123;                        // 替换数据                        skuInfo.setName(highlightFields.get("name").getFragments()[0].toString());                      &#125;                      list.add((T) skuInfo);                    &#125;                  &#125;                  return new AggregatedPageImpl&lt;T&gt;(                      list, pageable, searchHits.getTotalHits(), searchResponse.getAggregations());                &#125;                @Nullable                @Override                public &lt;T&gt; T mapSearchHit(SearchHit searchHit, Class&lt;T&gt; aClass) &#123;                  return null;                &#125;              &#125;);      resultMap.put("rows", aggregatedPage.getContent());    &#125;    return null;  &#125;&#125;

一、修改pom.xml文件将默认的jar方式改为war：1234567&lt;groupId&gt;com.example&lt;/groupId&gt;&lt;artifactId&gt;application&lt;/artifactId&gt;&lt;version&gt;0.0.1-SNAPSHOT&lt;/version&gt;&lt;!--默认为jar方式--&gt;&lt;!--&lt;packaging&gt;jar&lt;/packaging&gt;--&gt;&lt;!--改为war方式--&gt;&lt;packaging&gt;war&lt;/packaging&gt;
二、排除内置的Tomcat容器（两种方式都可）：1.排除spring-boot-starter-web中的Tomcat12345678910&lt;dependency&gt;    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;    &lt;artifactId&gt;spring-boot-starter-web&lt;/artifactId&gt;    &lt;exclusions&gt;        &lt;exclusion&gt;            &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;            &lt;artifactId&gt;spring-boot-starter-tomcat&lt;/artifactId&gt;        &lt;/exclusion&gt;    &lt;/exclusions&gt;&lt;/dependency&gt;
2.添加依赖1234567&lt;dependency&gt;    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;    &lt;artifactId&gt;spring-boot-starter-tomcat&lt;/artifactId&gt;    &lt;!--打包的时候可以不用包进去，别的设施会提供。事实上该依赖理论上可以参与编译，测试，运行等周期。        相当于compile，但是打包阶段做了exclude操作--&gt;    &lt;scope&gt;provided&lt;/scope&gt;&lt;/dependency&gt;
三、继承org.springframework.boot.web.servlet.support.SpringBootServletInitializer，实现configure方法：1.方式一，启动类继承SpringBootServletInitializer实现configure：123456789101112@SpringBootApplicationpublic class Application extends SpringBootServletInitializer &#123;    public static void main(String[] args) &#123;        SpringApplication.run(Application.class, args);    &#125;    @Override    protected SpringApplicationBuilder configure(SpringApplicationBuilder builder) &#123;        return builder.sources(Application.class);    &#125;&#125;
2.方式二，新增加一个类继承SpringBootServletInitializer实现configure：123456789public class ServletInitializer extends SpringBootServletInitializer &#123;    @Override    protected SpringApplicationBuilder configure(SpringApplicationBuilder builder) &#123;        //此处的Application.class为带有@SpringBootApplication注解的启动类        return builder.sources(Application.class);    &#125;&#125;

解决方法12limit_req_zone 用来限制单位时间内的请求数，即速率限制,采用的漏桶算法 &quot;leaky bucket&quot;。limit_req_conn 用来限制同一时间连接数，即并发限制。
1.limit_req_zone 参数配置命令11limit_req_zone $binary_remote_addr zone=one:10m rate=1r/s;
123* 第一个参数：$binary_remote_addr 表示通过remote_addr这个标识来做限制，“binary_”的目的是缩写内存占用量，是限制同一客户端ip地址。* 第二个参数：zone=one:10m表示生成一个大小为10M，名字为one的内存区域，用来存储访问的频次信息。* 第三个参数：rate=1r/s表示允许相同标识的客户端的访问频次，这里限制的是每秒1次，还可以有比如30r/m的。
命令21limit_req zone=one burst=5 nodelay;
123* 第一个参数：zone=one 设置使用哪个配置区域来做限制，与上面limit_req_zone 里的name对应。* 第二个参数：burst=5，重点说明一下这个配置，burst爆发的意思，这个配置的意思是设置一个大小为5的缓冲区当有大量请求（爆发）过来时，超过了访问频次限制的请求可以先放到这个缓冲区内。* 第三个参数：nodelay，如果设置，超过访问频次而且缓冲区也满了的时候就会直接返回503，如果没有设置，则所有请求会等待排队
例12345678http &#123;	# 相同ip一秒只能访问一次    limit_req_zone $binary_remote_addr zone=one:10m rate=1r/s;    server &#123;        location /search/ &#123;            limit_req zone=one burst=5 nodelay;        &#125;&#125;
2.limit_conn_zone  参数配置这个模块用来限制单个IP的请求数。并非所有的连接都被计数。只有在服务器处理了请求并且已经读取了整个请求头时，连接才被计数。
命令1.1 设置个人请求IP的限流容量1limit_conn_zone $binary_remote_addr zone=addr:10m;
12* 第一个参数：$binary_remote_addr 表示通过remote_addr这个标识来做限制，“binary_”的目的是缩写内存占用量，是限制同一客户端ip地址。* 第二个参数：zone=one:10m表示生成一个大小为10M，名字为one的内存区域，用来存储访问的频次信息。
命令1.2 设置整个location对应的请求的并发容量配置1limit_conn_zone $server_name zone=perserver:10m;
12* 第一个参数：$server_name 限制同一server最大并发数。* 第二个参数：zone=perserver:10m表示生成一个大小为10M，名字为perserver的内存区域，用来存储访问的频次信息。
命令2123limit_conn perip 2; # 同一个ip只能响应两次limit_conn perserver 20; # 整个location并发总量20次limit_rate 100k;
12* limit_conn为限制并发连接数；* limit_rate为限制下载速度
例1234567891011http &#123;	    limit_conn_zone $binary_remote_addr zone=perip:10m;	limit_conn_zone $server_name zone=perserver:10m;    server &#123;        location /search/ &#123;            limit_conn perip 2;			limit_conn perserver 20;			limit_rate 100k;        &#125;&#125;

项目用例12
关于foreach标签,有几个属性应该注意一下:
属性描述123456collection	指定要遍历的集合,list类型的参数会特殊处理封装在map中，map的key就叫listitem	将当前遍历出的元素赋值给指定的变量separator	每个元素之间的分隔符open	遍历出所有结果拼接一个开始的字符close	遍历出所有结果拼接一个结束的字符index	索引。遍历list的时候是index就是索引，item就是当前值。遍历map的时候index表示的就是map的key，item就是map的值， #&#123;变量名&#125;就能取出变量的值也就是当前遍历出的元素。
一、使用MyBatis对表执行UPDATE批处理——基于XML的实现1、定义mapper接口方法123456789public interface UserMapper extends BaseDao&lt;UserModel&gt; &#123;    //Mybatis中进行批量更新1    public int updateBatch1(List&lt;User&gt;) throws Exception;    //Mybatis中进行批量更新2    public int updateBatch2(List&lt;User&gt;) throws Exception;&#125;
