t;	&lt;/bean&gt;	&lt;bean id="wall-config" class="com.alibaba.druid.wall.WallConfig"&gt;		&lt;!-- 批量sql --&gt;		&lt;property name="multiStatementAllow" value="true"/&gt;	&lt;/bean&gt;
