ControllerServletOutputStream.getOutputStream()获得字节流，通过该字节流的write(byte[] bytes)可以向response缓冲区中写入字节，再由Tomcat服务器将字节内容组成Http响应返回给浏览器。1234567891011121314151617181920212223242526272829303132333435@Controller@RequestMapping("/FileComponent")public class FileComponentController extends BaseController &#123;		@Autowired  	private  HttpServletResponse  response;		@Autowired	private zipUtil ziputil;		@RequestMapping(value ="/getZipFile")	@ResponseBody	public  void getZipFile() throws Exception&#123;						try &#123;						List&lt;String&gt; fileinfo = new ArrayList&lt;String&gt;();			fileinfo = fileBuild.creatTxtFile("111", "ziptest.txt", "192310");				System.out.println(fileinfo.get(1));				response.setContentType("application/zip");				response.setHeader("Content-Disposition", "attachment; filename=excel.zip");  			 ziputil.toZip(fileinfo.get(1), response.getOutputStream(),false);		&#125; catch (Exception e) &#123;			// TODO: handle exception			System.out.println(e.toString());		&#125;							&#125;			&#125;
zipUtil123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115@Componentpublic class zipUtil &#123;	 private static final int  BUFFER_SIZE = 2 * 1024;	     /**	      * 压缩成ZIP 方法	      * @param srcDir 压缩文件夹路径 	      * @param out    压缩文件输出流	      * @param KeepDirStructure  是否保留原来的目录结构,true:保留目录结构; 	      *                          false:所有文件跑到压缩包根目录下(注意：不保留目录结构可能会出现同名文件,会压缩失败)	      * @throws RuntimeException 压缩失败会抛出运行时异常	      */	     public static void toZip(String srcDir, OutputStream out, boolean KeepDirStructure)throws RuntimeException&#123;	         long start = System.currentTimeMillis();	         ZipOutputStream zos = null ;	         try &#123;	 	             zos = new ZipOutputStream(out);	             File sourceFile = new File(srcDir);	             compress(sourceFile,zos,sourceFile.getName(),KeepDirStructure);	 	         &#125; catch (Exception e) &#123;	             throw new RuntimeException("zip error from ZipUtils",e);	         &#125;finally&#123;	             if(zos != null)&#123;	                 try &#123;	                     zos.close();	                 &#125; catch (IOException e) &#123;	                     e.printStackTrace();	                 &#125;	 	             &#125;	 	         &#125;		     &#125;	     	     	     /**	          * 递归压缩方法	          * @param sourceFile 源文件	          * @param zos        zip输出流	          * @param name       压缩后的名称	          * @param KeepDirStructure  是否保留原来的目录结构,true:保留目录结构; 	          *                          false:所有文件跑到压缩包根目录下(注意：不保留目录结构可能会出现同名文件,会压缩失败)	          * @throws Exception	          */	         private static void compress(File sourceFile, ZipOutputStream zos, String name,boolean KeepDirStructure) throws Exception&#123;	     	             byte[] buf = new byte[BUFFER_SIZE];	     	             if(sourceFile.isFile())&#123;	    	                 // 向zip输出流中添加一个zip实体，构造器中name为zip实体的文件的名字	 	                 zos.putNextEntry(new ZipEntry(name));	     	                 // copy文件到zip输出流中	     	                 int len;	     	                 FileInputStream in = new FileInputStream(sourceFile);	     	                 while ((len = in.read(buf)) != -1)&#123;	     	                     zos.write(buf, 0, len);	     	                 &#125;	     	                // Complete the entry	                 zos.closeEntry();	                 in.close();	     	             &#125; else &#123;	     	                 File[] listFiles = sourceFile.listFiles();	     	                 if(listFiles == null || listFiles.length == 0)&#123;	     	                     // 需要保留原来的文件结构时,需要对空文件夹进行处理	                     if(KeepDirStructure)&#123;	     	                         // 空文件夹的处理	                         zos.putNextEntry(new ZipEntry(name + "/"));	     	                         // 没有文件，不需要文件的copy	                        zos.closeEntry();	     	                     &#125;	                 &#125;else &#123;	     	                     for (File file : listFiles) &#123;	     	                         // 判断是否需要保留原来的文件结构	     	                         if (KeepDirStructure) &#123;	     	                             // 注意：file.getName()前面需要带上父文件夹的名字加一斜杠,	     	                             // 不然最后压缩包中就不能保留原来的文件结构,即：所有文件都跑到压缩包根目录下了	     	                             compress(file, zos, name + "/" + file.getName(),KeepDirStructure);	     	                         &#125; else &#123;	     	                             compress(file, zos, file.getName(),KeepDirStructure);	     	                         &#125;	                     &#125;	     	                 &#125;	     	             &#125;	     	         &#125;&#125;
fileUtil1234567891011121314151617181920212223242526272829303132333435363738394041public class fileBuild &#123;		public static List&lt;String&gt; creatTxtFile(String info,String filename , String storecd) throws IOException &#123;				List&lt;String&gt; fileinfo = new ArrayList&lt;String&gt;();		DateFormat df = new SimpleDateFormat("yyyyMMddHHmm");		Calendar calendar = Calendar.getInstance();		String dateName = df.format(calendar.getTime());		String name = storecd+dateName+"/";		//String path = "/src/main/webapp/WEB-INF/"+name;				String textpath = fileBuild.class.getResource("/").getPath()+name;		File filepath = new File(textpath);		filepath.mkdir();		String nowfilepath = (fileBuild.class.getResource("/").getPath()+name+filename);		nowfilepath = nowfilepath.substring(1,nowfilepath.length());		fileinfo.add(filename);		fileinfo.add(textpath);   		File file1 = new File(nowfilepath);				if (!file1.exists()) &#123;			file1.createNewFile();			  					BufferedWriter fileWriter =new BufferedWriter(new OutputStreamWriter(new FileOutputStream(file1),"UTF-8"));			//FileWriter fileWriter = new FileWriter(filename);  			fileWriter.write(info);  			fileWriter.flush();			fileWriter.close(); 					return fileinfo;					&#125;				return null;		 	&#125;&#125;
