例1：123456789101112131415/* author by w3cschool.cc Main.java */import java.util.*;public class Main &#123;   public static void main(String[] args) &#123;      List list = Arrays.asList("one Two three Four five six one three Four".split(" "));      System.out.println(list);      System.out.println("最大值: " + Collections.max(list));      System.out.println("最小值: " + Collections.min(list));   &#125;&#125;
