完成demodemo112345678910111213141516171819202122232425262728293031323334353637383940414243444546474849CREATE OR REPLACE procedure Pro_Sprk_Cancel(StoreHouseID varchar2,     InStockCode varchar2,      Registrar varchar2,    Operator1 varchar2  )as num number;drug_num number;cursor emp_cursor is select &quot;DrugCode&quot;,&quot;Total&quot;,&quot;Count&quot; as &quot;Count1&quot;,&quot;SellPrice&quot; ,&quot;Batch&quot;  from &quot;HPD_INSTOCK_TEMP&quot; where &quot;InStockCode&quot;=InStockCode;begin   for emp_c in emp_cursor LOOP        begin     select count(1) into drug_num from &quot;his_system_drug_info&quot;  where &quot;drug_no&quot;=emp_c.&quot;DrugCode&quot;;          select count(1) into num from &quot;his_pharmacy_storage&quot; where &quot;drug_no&quot; = emp_c.&quot;DrugCode&quot; and&quot;batch_group_no&quot;=emp_c.&quot;Batch&quot; and &quot;stock_qty&quot;&gt;=emp_c.&quot;Count1&quot;;     end;           if drug_num=0 or num =0 then      BEGIN       dbms_output.put_line(&apos;药品表中没有这个药品、库存明细表没有这个药品或数量大于库存数量&apos;);       rollback;        END;     else        begin        update &quot;his_pharmacy_storage&quot;        set &quot;stock_qty&quot; = &quot;stock_qty&quot; - emp_c.&quot;Count1&quot;,            &quot;stock_total_price&quot; = &quot;stock_total_price&quot; - emp_c.&quot;Total&quot;         where         &quot;drug_no&quot; = emp_c.&quot;DrugCode&quot;         and         &quot;batch_group_no&quot;=emp_c.&quot;Batch&quot;;          update  &quot;his_pharmacy_stockinfo&quot;         set &quot;stock_qty&quot; = &quot;stock_qty&quot; - emp_c.&quot;Count1&quot;,         &quot;stock_total_price&quot; = &quot;stock_total_price&quot; - emp_c.&quot;Total&quot;           where           &quot;drug_no&quot; = emp_c.&quot;DrugCode&quot;;         end;     end if;        END LOOP; commit; //没有错误就commit提交EXCEPTION  //捕捉错误，rollback ，返回提示信息 when others THEN  rollback; dbms_output.put_line(&apos;退库失败&apos;);end Pro_Sprk_Cancel;
 OR REPLACE PROCEDURE Pro_Sprk(         InStockCode  in varchar2 ,     Operator1    in varchar2   ) asdrug_num number;num number;storage_num number;cursor emp_cursor is select &quot;DrugCode&quot;,&quot;Total&quot;,&quot;Count&quot; as &quot;Count1&quot;,&quot;SellPrice&quot;,&quot;Manufacture&quot; ,&quot;Batch&quot; from &quot;HPD_PHARMACY_DETAIL&quot; where &quot;InStockCode&quot;= InStockCode; emp_c emp_cursor%rowtype;BEGIN dbms_output.put_line(&apos;遍历游标，将游标中的数据放入变量&apos;); --遍历游标，将游标中的数据放入变量 for  emp_c in emp_cursor LOOP--判断药品表中是否有这个药品beginselect count(1) into drug_num from &quot;his_system_drug_info&quot; where &quot;drug_no&quot;=emp_c.&quot;DrugCode&quot;;end;if drug_num=0 then   --药品表中没有这一条数据,回滚  begin   dbms_output.put_line(&apos;药品表中没有这个药品&apos;);   rollback;  end;end if;--判断库存表中是否有这个编号的药品beginselect count(1) into num from &quot;his_pharmacy_stockinfo&quot; where &quot;drug_no&quot;= emp_c.&quot;DrugCode&quot;;end;--有的话更新库存表的金额和数量if num&gt;0 then  --更新库存表金额和数量dbms_output.put_line(&apos;更新库存表金额和数量&apos;);  beginupdate  &quot;his_pharmacy_stockinfo&quot;set &quot;stock_qty&quot; = &quot;stock_qty&quot; + emp_c.&quot;Count1&quot;,      &quot;stock_total_price&quot; = &quot;stock_total_price&quot; + emp_c.&quot;Total&quot;    where      &quot;drug_no&quot; = emp_c.&quot;DrugCode&quot;;end;  else  --没有就新增一条库存记录begindbms_output.put_line(&apos;1&apos;);insert into &quot;his_pharmacy_stockinfo&quot;(&quot;id&quot; ,&quot;drug_no&quot;,&quot;drug_name&quot;,&quot;drug_type&quot;,&quot;system_type&quot;,&quot;retail_price&quot;,&quot;stock_qty&quot;,&quot;stock_total_price&quot;,&quot;preout_sum&quot;,&quot;preout_total_price&quot;,&quot;lack_flag&quot;,&quot;unit_flag&quot;,&quot;min_sum&quot;,&quot;operator_name&quot;,&quot;operator_time&quot;)selectHIS_PHARMACY_STOCKINFO_SEQ.NEXTVAL,&quot;drug_no&quot;,&quot;drug_name&quot;,&quot;drug_type&quot;,&quot;system_type&quot;,emp_c.&quot;SellPrice&quot;, emp_c.&quot;Count1&quot;, emp_c.&quot;Total&quot;, 0, 0, 0, 0, 1, Operator1, SYSDATE from &quot;his_system_drug_info&quot; where &quot;drug_no&quot;= emp_c.&quot;DrugCode&quot;;end;end if;begin  select count(1) into storage_num from &quot;his_pharmacy_storage&quot; where &quot;drug_no&quot;= emp_c.&quot;DrugCode&quot; and &quot;batch_group_no&quot;=emp_c.&quot;Batch&quot;;end;if storage_num&gt;0 then  begin  update &quot;his_pharmacy_storage&quot;  set &quot;stock_qty&quot; = &quot;stock_qty&quot; + emp_c.&quot;Count1&quot;,      &quot;stock_total_price&quot; = &quot;stock_total_price&quot; + emp_c.&quot;Total&quot;    where      &quot;drug_no&quot; = emp_c.&quot;DrugCode&quot;      and      &quot;batch_group_no&quot;=emp_c.&quot;Batch&quot;;   end;elsebegindbms_output.put_line(&apos;2&apos;);insert into &quot;his_pharmacy_storage&quot; (&quot;id&quot;,--  ID&quot;drug_no&quot;,-- 药品编码&quot;drug_name&quot;,-- 药品名称&quot;drug_spell_no&quot;,-- 商品名拼音码&quot;drug_wb_no&quot;,--  商品名五笔码&quot;drug_define_no&quot;,  --商品名自定义码&quot;drug_regular_name&quot;, --通用名&quot;drug_regular_spell_no&quot;, --通用名拼音码&quot;drug_regular_wb_no&quot;,--  通用名五笔码&quot;drug_regular_define_no&quot;,--  通用名自定义码&quot;drug_formal_name&quot;,--  学名&quot;drug_formal_spell_no&quot;,--  学名拼音码&quot;drug_formal_wb_no&quot;,-- 学名五笔码&quot;drug_formal_define_no&quot;,-- 学名自定义码&quot;drug_alias_name&quot;,-- 别名&quot;drug_alias_spell_no&quot;,-- 别名拼音码&quot;drug_alias_wb_no&quot;,--  别名五笔码&quot;drug_alias_define_no&quot;,--  别名自定义码&quot;drug_regular_english_name&quot;,-- 英文通用名&quot;drug_english_alias_name&quot;,-- 英文别名&quot;drug_english_name&quot;,-- 英文名&quot;international_no&quot;,--  国际编码&quot;country_no&quot;,--  国家编码&quot;specs&quot;,&quot;producer&quot;,&quot;drug_type&quot;,&quot;system_type&quot;,&quot;batch_group_no&quot;,&quot;retail_price&quot;,--  零售价&quot;base_dose&quot;,-- 基本剂量&quot;drug_split_type&quot;,-- 拆分类型&quot;valid_state&quot;,-- 有效性标志&quot;madeself_flag&quot;,-- 自制标志&quot;test_flag&quot;,-- 是否需要试敏&quot;gmp_flag&quot;,--  GMP标志&quot;otc_flag&quot;,--  O