LIMIT是MySQL内置函数，其作用是用于限制查询结果的条数。1)其语法格式如下:
LIMIT[位置偏移量,]行数
其中，中括号里面的参数是可选参数，位置偏移量是指MySQL查询分析器要从哪一行开始显示，索引值从0开始，即第一条记录位置偏移量是0，第二条记录的位置偏移量是1,依此类推…，第二个参数为“行数”即指示返回的记录条数。
位置偏移量可以理解为跳过前xx条记录(元组).
2)基本用法123456/*当没有指定位置偏移量时，只取4条时，可以这样写*/SELECT * FROM YourTableName LIMIT 4; /*当指定了位置偏移量时，从第3条起取4条时，可以这样写*//*因为索引是从0开始计数的，所以第3条对应的索引就是2*/SELECT * FROM YourTableName LIMIT 2,4;
3)应用场合:分页123456 // 后台计算出页码、页数(页大小) int curPage = 2; int pageSize = 10; int startRow = (curPage - 1) * pageSize;SELECT * FROM YourTableName LIMIT startRow,pageSize;

package com.fh.controller.tts;import com.fh.controller.base.BaseController;import com.fh.util.AppUtil;import com.fh.util.PageData;import com.fh.util.common.DemoException;import com.fh.util.common.ConnUtil;import com.fh.util.common.TokenHolder;import com.mysql.fabric.Response;import org.apache.http.HttpResponse;import org.springframework.http.HttpRequest;import org.springframework.stereotype.Controller;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.ResponseBody;
import javax.servlet.http.HttpServletResponse;import java.io.*;import java.net.HttpURLConnection;import java.net.URL;import java.util.HashMap;import java.util.Map;
@Controller@RequestMapping(value = “/api/tts/voice”)public class TtsMain extends BaseController {
//  填写网页上申请的appkey 如 $apiKey=&quot;g8eBUMSokVB1BHGmgxxxxxx&quot;
private final String appKey = &quot;4E1BG9lTnlSeIf1NQFlrSq6h&quot;;

// 填写网页上申请的APP SECRET 如 $secretKey=&quot;94dc99566550d87f8fa8ece112xxxxx&quot;
private final String secretKey = &quot;544ca4657ba8002e3dea3ac2f5fdd241&quot;;


// text 的内容为&quot;欢迎使用百度语音合成&quot;的urlencode,utf-8 编码
// 可以百度搜索&quot;urlencode&quot;
// private final String text = &quot;欢迎使用百度语音&quot;;

// 发音人选择, 0为普通女声，1为普通男生，3为情感合成-度逍遥，4为情感合成-度丫丫，默认为普通女声
private final int per = 0;
// 语速，取值0-9，默认为5中语速
private final int spd = 5;
// 音调，取值0-9，默认为5中语调
private final int pit = 5;
// 音量，取值0-9，默认为5中音量
private final int vol = 5;

public final String url = &quot;http://tsn.baidu.com/text2audio&quot;; // 可以使用https

private String cuid = &quot;1234567JAVA&quot;;

@RequestMapping(value = &quot;/text2audio.mp3&quot;)
private Object run(HttpServletResponse response
) throws IOException, DemoException {

    PageData pd = new PageData();
    pd = this.getPageData();
    Map&lt;String, Object&gt; map = new HashMap&lt;&gt;();
    int resultCode = 0;


    TokenHolder holder = new TokenHolder(appKey, secretKey, TokenHolder.ASR_SCOPE);
    holder.resfresh();
    String token = holder.getToken();
    if (pd.isValueNotEmpty(&quot;text&quot;) == false){

        map.put(&quot;error_info&quot;,&quot;text不能为空&quot;);
        resultCode= -1;

} else {

        String url2 = url + &quot;?tex=&quot; + ConnUtil.urlEncode(pd.getString(&quot;text&quot;));
        url2 += &quot;&amp;per=&quot; + per;
        url2 += &quot;&amp;spd=&quot; + spd;
        url2 += &quot;&amp;pit=&quot; + pit;
        url2 += &quot;&amp;vol=&quot; + vol;
        url2 += &quot;&amp;cuid=&quot; + cuid;
        url2 += &quot;&amp;tok=&quot; + token;
        url2 += &quot;&amp;lan=zh&amp;ctp=1&quot;;
        // System.out.println(url2); // 反馈请带上此url，浏览器上可以测试
        HttpURLConnection conn = (HttpURLConnection) new URL(url2).openConnection();
        conn.setConnectTimeout(5000);
        String contentType = conn.getContentType();
        if (contentType.contains(&quot;mp3&quot;)) {
            byte[] bytes = ConnUtil.getResponseBytes(conn);

            OutputStream out = response.getOutputStream();
            out.write(bytes);
            out.flush();
            out.close();

        }
    }

    map.put(&quot;result_code&quot;,resultCode);
    return AppUtil.returnObject(new PageData(),map);
}
}

