propertyConfigurer读取dbconfig数据库连接信息，通过org.springframework.beans.factory.config.PropertyPlaceholderConfigurer 将dbcongfig的信息返回给阿里 druid数据库连接池12345678&lt;bean id=&quot;propertyConfigurer&quot; class=&quot;org.springframework.beans.factory.config.PropertyPlaceholderConfigurer&quot;&gt;    &lt;property name=&quot;locations&quot;&gt;        &lt;list&gt;            &lt;value&gt;/WEB-INF/classes/dbconfig.properties&lt;/value&gt;        &lt;/list&gt;    &lt;/property&gt;&lt;/bean&gt;




阿里 druid数据库连接池，通过${}获得org.springframework.beans.factory.config.PropertyPlaceholderConfigurer 吐出的数据参考文档 ：https://www.cnblogs.com/wuyun-blog/p/5679073.html
123456789101112131415161718192021222324252627282930313233&lt;!-- 阿里 druid数据库连接池 --&gt;&lt;bean id=&quot;dataSource&quot; class=&quot;com.alibaba.druid.pool.DruidDataSource&quot; destroy-method=&quot;close&quot;&gt;    &lt;!-- 数据库基本信息配置 --&gt;    &lt;property name=&quot;url&quot; value=&quot;$&#123;url&#125;&quot; /&gt;    &lt;property name=&quot;username&quot; value=&quot;$&#123;username&#125;&quot; /&gt;    &lt;property name=&quot;password&quot; value=&quot;$&#123;password&#125;&quot; /&gt;    &lt;property name=&quot;driverClassName&quot; value=&quot;$&#123;driverClassName&#125;&quot; /&gt;    &lt;property name=&quot;filters&quot; value=&quot;$&#123;filters&#125;&quot; /&gt; --属性类型是字符串，通过别名的方式配置扩展插件，常用的插件有： 监控统计用的filter:stat日志用的filter:log4j防御sql注入的filter:wall		    &lt;!-- 最大并发连接数 --&gt;    &lt;property name=&quot;maxActive&quot; value=&quot;$&#123;maxActive&#125;&quot; /&gt;    &lt;!-- 初始化连接数量 --&gt;    &lt;property name=&quot;initialSize&quot; value=&quot;$&#123;initialSize&#125;&quot; /&gt;    &lt;!-- 配置获取连接等待超时的时间 --&gt;    &lt;property name=&quot;maxWait&quot; value=&quot;$&#123;maxWait&#125;&quot; /&gt;    &lt;!-- 最小空闲连接数 --&gt;    &lt;property name=&quot;minIdle&quot; value=&quot;$&#123;minIdle&#125;&quot; /&gt;    &lt;!-- 配置间隔多久才进行一次检测，检测需要关闭的空闲连接，单位是毫秒 --&gt;    &lt;property name=&quot;timeBetweenEvictionRunsMillis&quot; value=&quot;$&#123;timeBetweenEvictionRunsMillis&#125;&quot; /&gt;    &lt;!-- 配置一个连接在池中最小生存的时间，单位是毫秒 --&gt;    &lt;property name=&quot;minEvictableIdleTimeMillis&quot; value=&quot;$&#123;minEvictableIdleTimeMillis&#125;&quot; /&gt;    &lt;property name=&quot;validationQuery&quot; value=&quot;$&#123;validationQuery&#125;&quot; /&gt;    &lt;property name=&quot;testWhileIdle&quot; value=&quot;$&#123;testWhileIdle&#125;&quot; /&gt;    &lt;property name=&quot;testOnBorrow&quot; value=&quot;$&#123;testOnBorrow&#125;&quot; /&gt;    &lt;property name=&quot;testOnReturn&quot; value=&quot;$&#123;testOnReturn&#125;&quot; /&gt;    &lt;property name=&quot;maxOpenPreparedStatements&quot; value=&quot;$&#123;maxOpenPreparedStatements&#125;&quot; /&gt;    &lt;!-- 打开removeAbandoned功能 --&gt;    &lt;property name=&quot;removeAbandoned&quot; value=&quot;$&#123;removeAbandoned&#125;&quot; /&gt;    &lt;!-- 1800秒，也就是30分钟 --&gt;    &lt;property name=&quot;removeAbandonedTimeout&quot; value=&quot;$&#123;removeAbandonedTimeout&#125;&quot; /&gt;    &lt;!-- 关闭abanded连接时输出错误日志 --&gt;    &lt;property name=&quot;logAbandoned&quot; value=&quot;$&#123;logAbandoned&#125;&quot; /&gt;&lt;/bean&gt;
3 .mybatis调用sqlSessionFactory
1234567891011&lt;!-- 配置mybatis --&gt;    &lt;bean id=&quot;sqlSessionFactory&quot; class=&quot;org.mybatis.spring.SqlSessionFactoryBean&quot;&gt;        &lt;property name=&quot;dataSource&quot; ref=&quot;dataSource&quot; /&gt;        &lt;property name=&quot;configLocation&quot; value=&quot;classpath:mybatis/mybatis-config.xml&quot;&gt;&lt;/property&gt;        &lt;!-- mapper扫描 --&gt;        &lt;property name=&quot;mapperLocations&quot; value=&quot;classpath:mybatis/*/*.xml&quot;&gt;&lt;/property&gt;    &lt;/bean&gt;    &lt;bean id=&quot;sqlSessionTemplate&quot; class=&quot;org.mybatis.spring.SqlSessionTemplate&quot;&gt;        &lt;constructor-arg ref=&quot;sqlSessionFactory&quot; /&gt;    &lt;/bean&gt;


java逻辑代码实现dao层使用sql获取数据库信息123456789101112131415@Repository(&quot;daoSupport&quot;)public class DaoSupport implements DAO &#123;@Resource(name = &quot;sqlSessionTemplate&quot;)	private SqlSessionTemplate sqlSessionTemplate;		/**	 * 保存对象	 * @param str	 * @param obj	 * @return	 * @throws Exception	 */	public Object save(String str, Object obj) throws Exception &#123;return sqlSessionTemplate.insert(str, obj);&#125;
